import {
  Mjml,
  MjmlBody,
  MjmlButton,
  MjmlColumn,
  MjmlFont,
  MjmlHead,
  MjmlImage,
  MjmlPreview,
  MjmlSection,
  MjmlSpacer,
  MjmlText,
  MjmlWrapper,
} from "@faire/mjml-react";

import { defaultTheme } from "@/components/email/theme-default";
import type { EmailThemeTokens } from "@/components/email/theme-default";

export type CategoryPreviewRowsVariant =
  | "basic"
  | "with-header"
  | "with-description"
  | "header-description"
  | "with-details"
  | "header-details"
  | "full-details"
  | "header-full-details";

export interface CategoryPreviewRowsProps {
  theme?: EmailThemeTokens;
  variant?: CategoryPreviewRowsVariant;
  heading?: string;
  intro?: string;
  imageSrc1?: string;
  imageSrc2?: string;
  name1?: string;
  name2?: string;
  price1?: string;
  price2?: string;
  description1?: string;
  description2?: string;
  ctaLabel?: string;
}

const fontFamily =
  'Inter, ui-sans-serif, system-ui, -apple-system, "Segoe UI", sans-serif';

const variantFeatures = (variant: CategoryPreviewRowsVariant) => ({
  description:
    variant === "with-description" ||
    variant === "header-description" ||
    variant === "full-details" ||
    variant === "header-full-details",
  details:
    variant === "with-details" ||
    variant === "header-details" ||
    variant === "full-details" ||
    variant === "header-full-details",
  header:
    variant === "with-header" ||
    variant === "header-description" ||
    variant === "header-details" ||
    variant === "header-full-details",
});

const CategoryRow = ({
  ctaLabel,
  description,
  details,
  imageSrc,
  name,
  price,
  second,
}: {
  ctaLabel: string;
  description: string;
  details: boolean;
  imageSrc: string;
  name: string;
  price: string;
  second: boolean;
}) => (
  <MjmlSection backgroundColor="#fffffe" padding="0 24px">
    <MjmlColumn padding="0 24px 0 0" verticalAlign="top" width="212px">
      <MjmlImage
        alt={name}
        borderRadius="8px"
        padding="0"
        src={imageSrc}
        width="188px"
      />
    </MjmlColumn>
    <MjmlColumn padding="0" verticalAlign="top">
      <MjmlText
        color="#030712"
        fontFamily={fontFamily}
        fontSize="20px"
        fontWeight="600"
        lineHeight="28px"
        padding="0"
      >
        {name}
      </MjmlText>
      <MjmlText
        color="#030712"
        fontFamily={fontFamily}
        fontSize="20px"
        fontWeight="500"
        lineHeight="28px"
        padding="12px 0 0"
      >
        {price}
      </MjmlText>
      <MjmlSpacer height="24px" />
      {details ? (
        <>
          <MjmlText
            color="#4b5563"
            fontFamily={fontFamily}
            fontSize="16px"
            fontWeight="300"
            lineHeight="24px"
            padding="0"
          >
            {description}
          </MjmlText>
          <MjmlSpacer height="28px" />
          <MjmlText
            color="#4b5563"
            fontFamily={fontFamily}
            fontSize="14px"
            lineHeight="20px"
            padding="0"
          >
            Colors: Black, White, Gray{second ? "" : ", Mint"}
          </MjmlText>
          <MjmlSpacer height="24px" />
        </>
      ) : null}
      <MjmlButton
        align="left"
        backgroundColor="#4f46e5"
        borderRadius="8px"
        color="#fffffe"
        fontFamily={fontFamily}
        fontSize="16px"
        fontWeight="500"
        href={
          second ? "https://example.com/pants" : "https://example.com/shoes"
        }
        innerPadding="14px 20px"
        lineHeight="16px"
        padding="0"
      >
        {ctaLabel} →
      </MjmlButton>
    </MjmlColumn>
  </MjmlSection>
);

export const CategoryPreviewRowsSection = ({
  ctaLabel = "Shop now",
  description1 = "Soft, breathable, and effortlessly stylish. Made for comfort and everyday wear with a clean, minimal edge.",
  description2 = "Designed for comfort and movement with a refined fit and modern silhouette — your go-to for everyday versatility.",
  heading = "Our products",
  imageSrc1 = "https://emailcn.vercel.app/api/email-assets/category-previews/portrait-1.jpg",
  imageSrc2 = "https://emailcn.vercel.app/api/email-assets/category-previews/portrait-2.jpg",
  intro = "Style meets purpose in every piece. Designed with attention to detail and built for everyday comfort, our collection brings together modern design, timeless quality, and effortlessness.",
  name1 = "Sweatshirts",
  name2 = "Pants",
  price1 = "$40.00-69.00",
  price2 = "$70.00-120.00",
  variant = "with-header",
}: Omit<CategoryPreviewRowsProps, "theme">) => {
  const features = variantFeatures(variant);

  return (
    <>
      <MjmlSection backgroundColor="#fffffe" padding="44px 24px">
        <MjmlColumn padding="0">
          {features.header ? (
            <>
              <MjmlText
                align="center"
                color="#030712"
                fontFamily={fontFamily}
                fontSize="30px"
                fontWeight="600"
                lineHeight="36px"
                padding="0"
              >
                {heading}
              </MjmlText>
              <MjmlSpacer height="44px" />
            </>
          ) : null}
          {features.description ? (
            <MjmlText
              align="center"
              color="#4b5563"
              fontFamily={fontFamily}
              fontSize="18px"
              lineHeight="28px"
              padding="0"
            >
              {intro}
            </MjmlText>
          ) : null}
        </MjmlColumn>
      </MjmlSection>
      <CategoryRow
        ctaLabel={ctaLabel}
        description={description1}
        details={features.details}
        imageSrc={imageSrc1}
        name={name1}
        price={price1}
        second={false}
      />
      <MjmlSection backgroundColor="#fffffe" padding="0">
        <MjmlColumn padding="0">
          <MjmlSpacer height="44px" />
        </MjmlColumn>
      </MjmlSection>
      <CategoryRow
        ctaLabel={ctaLabel}
        description={description2}
        details={features.details}
        imageSrc={imageSrc2}
        name={name2}
        price={price2}
        second
      />
      <MjmlSection backgroundColor="#fffffe" padding="0">
        <MjmlColumn padding="0">
          <MjmlSpacer height="44px" />
        </MjmlColumn>
      </MjmlSection>
    </>
  );
};

export const CategoryPreviewRows = ({
  theme = defaultTheme,
  ...props
}: CategoryPreviewRowsProps) => (
  <Mjml>
    <MjmlHead>
      <MjmlPreview>Our products</MjmlPreview>
      <MjmlFont href="https://rsms.me/inter/inter.css" name="Inter" />
    </MjmlHead>
    <MjmlBody backgroundColor="#f1f5f9" width={theme.containerWidth}>
      <MjmlWrapper padding="0">
        <CategoryPreviewRowsSection {...props} />
      </MjmlWrapper>
    </MjmlBody>
  </Mjml>
);

CategoryPreviewRows.PreviewProps = {
  theme: defaultTheme,
  variant: "with-header",
} satisfies CategoryPreviewRowsProps;
